import pytest
import requests

def test_create_procedure_boundary_future_timestamp_max_precision(base_url, encounter_id):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "code": {"text": "Far-Future Procedure"},
        "performedDateTime": "9999-12-31T23:59:59Z",
        "encounter": {"reference": f"Encounter/{encounter_id}"}
    }
    resp = requests.post(f"{base_url}/Procedure", json=payload)
    assert resp.status_code in (201, 422), (
        f"Expected 201 or 422, got {resp.status_code}"
    )
    if resp.status_code == 201:
        assert resp.json()["performedDateTime"] == "9999-12-31T23:59:59Z"
    else:
        body = resp.json()
        assert "error" in body or "issue" in body
